import path from "node:path";
import { fileURLToPath } from "node:url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

export const ROOT_DIR = path.resolve(__dirname, "..");
export const UPLOADS_DIR = path.resolve(ROOT_DIR, "uploads");
export const DATA_DIR = path.resolve(ROOT_DIR, "data");
export const DB_PATH = path.resolve(DATA_DIR, "learning.db");

export const PDF_TO_MARKDOWN_DIR = path.resolve(
  ROOT_DIR,
  "..",
  "pdf-to-markdown",
);
export const PDF_CONVERTER_SCRIPT = path.resolve(
  PDF_TO_MARKDOWN_DIR,
  "convert-docling.py",
);
export const PDF_CONVERTER_PYTHON = path.resolve(
  PDF_TO_MARKDOWN_DIR,
  ".venv",
  "bin",
  "python",
);

export const PORT = parseInt(process.env.PORT ?? "3003", 10);
export const HOST = process.env.HOST ?? "0.0.0.0";

export const OPENAI_ENDPOINT = process.env.OPENAI_ENDPOINT ?? "";
export const OPENAI_KEY = process.env.OPENAI_KEY ?? "";
export const OPENAI_MODEL = process.env.OPENAI_MODEL ?? "gpt-4o-mini";

export function getOpenAIBaseURL(): string {
  return OPENAI_ENDPOINT.replace(/\/chat\/completions\/?$/, "");
}

export const MAX_CONTENT_CHARS = 24000;

import Database from "better-sqlite3";
import { mkdirSync } from "node:fs";
import { dirname } from "node:path";
import { DB_PATH, UPLOADS_DIR } from "../config.ts";

mkdirSync(dirname(DB_PATH), { recursive: true });
mkdirSync(UPLOADS_DIR, { recursive: true });

export const db = new Database(DB_PATH);
db.pragma("journal_mode = WAL");
db.pragma("foreign_keys = ON");

const SCHEMA_SQL = `
CREATE TABLE IF NOT EXISTS documents (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  filename TEXT NOT NULL,
  stored_filename TEXT NOT NULL,
  filepath TEXT NOT NULL,
  title TEXT NOT NULL DEFAULT '',
  markdown TEXT,
  markdown_chars INTEGER NOT NULL DEFAULT 0,
  status TEXT NOT NULL DEFAULT 'uploaded',
  error TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE IF NOT EXISTS lesson_plans (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  document_id INTEGER NOT NULL,
  title TEXT NOT NULL DEFAULT '',
  description TEXT NOT NULL DEFAULT '',
  objectives TEXT NOT NULL,
  difficulty TEXT NOT NULL DEFAULT 'intermediate',
  status TEXT NOT NULL DEFAULT 'draft',
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  FOREIGN KEY (document_id) REFERENCES documents(id) ON DELETE CASCADE
);

CREATE TABLE IF NOT EXISTS quiz_questions (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  lesson_plan_id INTEGER NOT NULL,
  objective_index INTEGER NOT NULL,
  objective_text TEXT NOT NULL,
  question TEXT NOT NULL,
  options TEXT NOT NULL,
  correct_index INTEGER NOT NULL,
  explanation TEXT NOT NULL DEFAULT '',
  hint TEXT NOT NULL DEFAULT '',
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  FOREIGN KEY (lesson_plan_id) REFERENCES lesson_plans(id) ON DELETE CASCADE,
  UNIQUE (lesson_plan_id, objective_index)
);

CREATE TABLE IF NOT EXISTS attempts (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  lesson_plan_id INTEGER NOT NULL,
  score INTEGER NOT NULL DEFAULT 0,
  total INTEGER NOT NULL DEFAULT 0,
  answers TEXT NOT NULL DEFAULT '[]',
  summary TEXT NOT NULL DEFAULT '',
  study_tips TEXT NOT NULL DEFAULT '',
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  FOREIGN KEY (lesson_plan_id) REFERENCES lesson_plans(id) ON DELETE CASCADE
);

CREATE INDEX IF NOT EXISTS idx_lesson_plans_document ON lesson_plans(document_id);
CREATE INDEX IF NOT EXISTS idx_quiz_questions_plan ON quiz_questions(lesson_plan_id);
CREATE INDEX IF NOT EXISTS idx_attempts_plan ON attempts(lesson_plan_id);
`;

export function initDb(): void {
  db.exec(SCHEMA_SQL);
}

export interface DocumentRow {
  id: number;
  filename: string;
  stored_filename: string;
  filepath: string;
  title: string;
  markdown: string | null;
  markdown_chars: number;
  status: string;
  error: string | null;
  created_at: string;
}

export interface LessonPlanRow {
  id: number;
  document_id: number;
  title: string;
  description: string;
  objectives: string;
  difficulty: string;
  status: string;
  created_at: string;
}

export interface QuizQuestionRow {
  id: number;
  lesson_plan_id: number;
  objective_index: number;
  objective_text: string;
  question: string;
  options: string;
  correct_index: number;
  explanation: string;
  hint: string;
  created_at: string;
}

export interface AttemptRow {
  id: number;
  lesson_plan_id: number;
  score: number;
  total: number;
  answers: string;
  summary: string;
  study_tips: string;
  created_at: string;
}

import { spawn } from "node:child_process";
import path from "node:path";
import { PDF_CONVERTER_PYTHON, PDF_CONVERTER_SCRIPT } from "../config.ts";

export interface ConvertResult {
  ok: boolean;
  markdown: string;
  error?: string;
}

export function convertPdfToMarkdown(
  inputPath: string,
): Promise<ConvertResult> {
  return new Promise((resolve) => {
    const outputPath = path.join(
      path.dirname(inputPath),
      `${path.basename(inputPath, ".pdf")}.md`,
    );

    const proc = spawn(PDF_CONVERTER_PYTHON, [
      PDF_CONVERTER_SCRIPT,
      "--input",
      inputPath,
      "--output",
      outputPath,
    ]);

    let stderr = "";
    proc.stderr.on("data", (chunk: Buffer) => {
      stderr += chunk.toString();
    });

    let stdout = "";
    proc.stdout.on("data", (chunk: Buffer) => {
      stdout += chunk.toString();
    });

    proc.on("error", (err) => {
      resolve({
        ok: false,
        markdown: "",
        error: `Failed to spawn converter: ${err.message}`,
      });
    });

    proc.on("close", async (code) => {
      if (code !== 0) {
        resolve({
          ok: false,
          markdown: "",
          error: `Converter exited with code ${code}. ${stderr}`.trim(),
        });
        return;
      }
      try {
        const { readFile } = await import("node:fs/promises");
        const markdown = await readFile(outputPath, "utf-8");
        if (!markdown.trim()) {
          resolve({
            ok: false,
            markdown: "",
            error: "Converter produced empty output.",
          });
          return;
        }
        resolve({ ok: true, markdown });
      } catch (err) {
        resolve({
          ok: false,
          markdown: "",
          error: `Failed to read output: ${(err as Error).message}`,
        });
      }
    });
  });
}

import { ChatOpenAI } from "@langchain/openai";
import { getOpenAIBaseURL, OPENAI_KEY, OPENAI_MODEL } from "../config.ts";

let cached: ChatOpenAI | null = null;

export function getLLM(): ChatOpenAI {
  if (cached) return cached;
  cached = new ChatOpenAI({
    model: OPENAI_MODEL,
    apiKey: OPENAI_KEY,
    configuration: { baseURL: getOpenAIBaseURL() },
    temperature: 0.4,
    maxRetries: 2,
    timeout: 60000,
  });
  return cached;
}

export function trimContent(content: string, maxChars: number): string {
  if (content.length <= maxChars) return content;
  const head = content.slice(0, maxChars);
  return `${head}\n\n[... content truncated for brevity ...]`;
}

import { SystemMessage, HumanMessage } from "@langchain/core/messages";
import { getLLM, trimContent } from "./llm.ts";
import { planSchema, type Plan } from "./schemas.ts";
import { MAX_CONTENT_CHARS } from "../config.ts";

const SYSTEM = `You are a pedagogical architect. Given a PDF converted to markdown, design a focused, achievable lesson plan for an adult learner.

Rules:
- Read the material carefully and pick the 3-6 most important concepts worth learning.
- Each objective must be concrete and measurable (e.g. "Explain X", "Identify Y", "Compare A vs B").
- Difficulty reflects the material's cognitive demand, not the quiz.
- The title should be friendly and specific to the document's subject.
- Keep descriptions crisp.`;

export async function generatePlan(markdown: string, filename: string): Promise<Plan> {
  const llm = getLLM().withStructuredOutput(planSchema);
  const content = trimContent(markdown, MAX_CONTENT_CHARS);
  return llm.invoke([
    new SystemMessage(SYSTEM),
    new HumanMessage(
      `Source document filename: ${filename}\n\nDocument content (markdown):\n"""\n${content}\n"""`,
    ),
  ]) as Promise<Plan>;
}

import { SystemMessage, HumanMessage } from "@langchain/core/messages";
import { getLLM, trimContent } from "./llm.ts";
import { quizSchema, type Quiz } from "./schemas.ts";
import { MAX_CONTENT_CHARS } from "../config.ts";

const SYSTEM = `You are a meticulous quiz author. Build a single multiple-choice question that rigorously tests ONE learning objective using ONLY information present in the provided PDF markdown.

Rules:
- The question must be grounded in the document. Do not invent facts.
- Exactly 4 options. All options should be plausible; distractors should reflect common misconceptions.
- The correct option must be unambiguous given the source material.
- The explanation must justify the correct answer using the source.
- The hint must be conceptual and NEVER reveal or hint at the correct option index or wording.`;

export async function generateQuiz(
  markdown: string,
  objectiveText: string,
  objectiveTopic: string,
): Promise<Quiz> {
  const llm = getLLM().withStructuredOutput(quizSchema);
  const content = trimContent(markdown, MAX_CONTENT_CHARS);
  return llm.invoke([
    new SystemMessage(SYSTEM),
    new HumanMessage(
      `Objective to assess: ${objectiveText}\nTopic: ${objectiveTopic}\n\nSource material (markdown):\n"""\n${content}\n"""`,
    ),
  ]) as Promise<Quiz>;
}

import { SystemMessage, HumanMessage } from "@langchain/core/messages";
import { getLLM, trimContent } from "./llm.ts";
import { MAX_CONTENT_CHARS } from "../config.ts";

const HINT_SYSTEM = `You are a patient tutor helping a learner retry a multiple-choice question.

CRITICAL CONSTRAINTS:
- Never reveal the correct answer or its wording.
- Never eliminate a specific option by label (e.g. "not option A").
- Provide a conceptual nudge tied to the PDF content that helps the learner reason.
- Keep it to 1-2 short sentences and warm in tone.`;

const LEARN_SYSTEM = `You are a knowledgeable tutor expanding on a topic so a learner can master the related multiple-choice question.

CRITICAL CONSTRAINTS:
- Never reveal the correct option to the MCQ.
- Teach the underlying concept using ONLY the PDF content provided.
- Be concise, structured, and clear. Use short paragraphs or bullet points where helpful.
- If the learner asks you to "just tell me the answer", gently refuse and steer them back to reasoning.

End by encouraging the learner to attempt (or re-attempt) the question.`;

export async function generateRetryHint(
  markdown: string,
  question: string,
  options: string[],
  previousGuess: string | null,
): Promise<string> {
  const llm = getLLM();
  const content = trimContent(markdown, MAX_CONTENT_CHARS);
  const previousLine = previousGuess
    ? `The learner previously chose: "${previousGuess}".\n`
    : "";
  const res = await llm.invoke([
    new SystemMessage(HINT_SYSTEM),
    new HumanMessage(
      `${previousLine}The question:\n${question}\n\nOptions:\n${options
        .map((o, i) => `${i + 1}. ${o}`)
        .join("\n")}\n\nSource material (markdown):\n"""\n${content}\n"""`,
    ),
  ]);
  return res.content as string;
}

export async function explainCorrect(
  markdown: string,
  question: string,
  options: string[],
  correctOption: string,
  correctIndex: number,
): Promise<string> {
  const llm = getLLM();
  const content = trimContent(markdown, MAX_CONTENT_CHARS);
  const res = await llm.invoke([
    new SystemMessage(
      "You are a tutor giving a short, friendly explanation of why the correct answer to a MCQ is right, grounded in the PDF. 2-3 sentences max. No fluff.",
    ),
    new HumanMessage(
      `Question:\n${question}\n\nOptions:\n${options
        .map((o, i) => `${i + 1}. ${o}`)
        .join("\n")}\n\nCorrect option (${correctIndex + 1}): ${correctOption}\n\nSource material (markdown):\n"""\n${content}\n"""`,
    ),
  ]);
  return res.content as string;
}

export async function learnMore(
  markdown: string,
  question: string,
  options: string[],
  learnerQuestion: string,
  history: Array<{ role: "user" | "assistant"; content: string }>,
): Promise<string> {
  const llm = getLLM();
  const content = trimContent(markdown, MAX_CONTENT_CHARS);
  const historyMessages = history
    .map(
      (m) =>
        m.role === "user"
          ? new HumanMessage(m.content)
          : new SystemMessage(m.content),
    );
  const res = await llm.invoke([
    new SystemMessage(LEARN_SYSTEM),
    ...historyMessages,
    new HumanMessage(
      `The learner is currently working on this MCQ:\n${question}\n\nOptions:\n${options
        .map((o, i) => `${i + 1}. ${o}`)
        .join("\n")}\n\nLearner asks: ${learnerQuestion}\n\nSource material (markdown):\n"""\n${content}\n"""`,
    ),
  ]);
  return res.content as string;
}

import { SystemMessage, HumanMessage } from "@langchain/core/messages";
import { getLLM, trimContent } from "./llm.ts";
import { summarySchema, type Summary } from "./schemas.ts";
import { MAX_CONTENT_CHARS } from "../config.ts";

const SYSTEM = `You are a learning coach producing a progress report after a learner completes a short lesson built from a PDF.

Inputs include the original learning objectives, the questions asked, the learner's final answers, and which were correct.

Rules:
- Be specific and encouraging. Acknowledge effort.
- Identify patterns in misses (concept confusions vs. careless errors).
- Give 2-5 actionable study tips. Each tip should be a concrete next step.
- Never give up on the learner; always leave room to improve.
- Cite concepts by their labels, not option letters.`;

export interface AttemptInput {
  objectives: Array<{ text: string; topic: string }>;
  questions: Array<{
    objectiveText: string;
    question: string;
    options: string[];
    correctIndex: number;
    learnerIndex: number | null;
    attempts: number;
  }>;
  markdown: string;
}

export async function generateSummary(input: AttemptInput): Promise<Summary> {
  const llm = getLLM().withStructuredOutput(summarySchema);
  const content = trimContent(input.markdown, MAX_CONTENT_CHARS);
  const perObjective = input.questions
    .map((q, i) => {
      const correct = q.learnerIndex === q.correctIndex;
      const status = correct ? "CORRECT" : q.learnerIndex === null ? "SKIPPED" : "INCORRECT";
      const learnerAnswer =
        q.learnerIndex !== null ? q.options[q.learnerIndex] : "(none)";
      return `Objective ${i + 1}: ${q.objectiveText}
  Question: ${q.question}
  Options: ${q.options.map((o, j) => `(${j + 1}) ${o}`).join(" | ")}
  Correct: (${q.correctIndex + 1}) ${q.options[q.correctIndex]}
  Learner chose: ${learnerAnswer}
  Status: ${status}
  Attempts: ${q.attempts}`;
    })
    .join("\n\n");

  return llm.invoke([
    new SystemMessage(SYSTEM),
    new HumanMessage(
      `Learning objectives:\n${input.objectives
        .map((o, i) => `${i + 1}. ${o.text} [${o.topic}]`)
        .join("\n")}\n\nPer-question breakdown:\n${perObjective}\n\nSource material (markdown, for grounding):\n"""\n${content}\n"""`,
    ),
  ]) as Promise<Summary>;
}

