import { useCallback, useRef, useState } from "react";
import { UploadCloud, FileText, Loader2 } from "lucide-react";
import { cn } from "#lib/utils";
import { uploadPdf } from "#lib/api";

interface Props {
  onUploaded: (documentId: number) => void;
}

export function UploadDropzone({ onUploaded }: Props) {
  const [dragging, setDragging] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const handleFile = useCallback(
    async (file: File) => {
      if (!file.name.toLowerCase().endsWith(".pdf")) {
        setError("Only PDF files are supported.");
        return;
      }
      setUploading(true);
      setError(null);
      try {
        const doc = await uploadPdf(file);
        onUploaded(doc.id);
      } catch (err) {
        setError((err as Error).message);
      } finally {
        setUploading(false);
      }
    },
    [onUploaded],
  );

  return (
    <div
      onDragOver={(e) => {
        e.preventDefault();
        setDragging(true);
      }}
      onDragLeave={() => setDragging(false)}
      onDrop={(e) => {
        e.preventDefault();
        setDragging(false);
        const file = e.dataTransfer.files?.[0];
        if (file) void handleFile(file);
      }}
      onClick={() => inputRef.current?.click()}
      role="button"
      tabIndex={0}
      onKeyDown={(e) => {
        if (e.key === "Enter" || e.key === " ") inputRef.current?.click();
      }}
      className={cn(
        "group relative flex cursor-pointer flex-col items-center justify-center rounded-2xl border-2 border-dashed bg-card p-10 text-center transition-all hover:border-primary/60 hover:bg-accent/40",
        dragging ? "border-primary bg-accent/60" : "border-border",
      )}
    >
      <input
        ref={inputRef}
        type="file"
        accept="application/pdf,.pdf"
        className="sr-only"
        onChange={(e) => {
          const file = e.target.files?.[0];
          if (file) void handleFile(file);
          e.target.value = "";
        }}
      />
      <div
        className={cn(
          "mb-4 flex size-14 items-center justify-center rounded-2xl bg-primary/10 text-primary transition-transform group-hover:scale-105",
          dragging && "scale-110",
        )}
      >
        {uploading ? (
          <Loader2 className="size-6 animate-spin" />
        ) : (
          <UploadCloud className="size-6" />
        )}
      </div>
      <p className="text-base font-medium">
        {uploading ? "Uploading & parsing PDF..." : "Drop your PDF here"}
      </p>
      <p className="mt-1 text-sm text-muted-foreground">
        or click to browse. We'll convert it to text and draft a lesson plan.
      </p>
      {error && (
        <p className="mt-3 inline-flex items-center gap-1.5 rounded-md bg-danger/10 px-3 py-1 text-xs font-medium text-danger">
          <FileText className="size-3.5" />
          {error}
        </p>
      )}
    </div>
  );
}

import { useNavigate } from "react-router-dom";
import {
  Clock,
  FileText,
  Loader2,
  AlertTriangle,
  RefreshCw,
  ChevronRight,
  Layers,
} from "lucide-react";
import { cn } from "#lib/utils";
import { Badge } from "#components/ui/badge";
import { Button } from "#components/ui/button";
import type { DocumentSummary } from "#lib/types";
import { difficultyLabel, formatDate } from "#lib/format";

interface Props {
  doc: DocumentSummary;
}

export function DocumentCard({ doc }: Props) {
  const navigate = useNavigate();
  const ready = doc.status === "ready";
  const processing = doc.status === "processing";
  const failed = doc.status === "failed";

  const start = () => {
    if (doc.plan) navigate(`/learn/${doc.plan.id}`);
  };

  const title = doc.title || doc.filename.replace(/\.pdf$/i, "");

  return (
    <div className="group flex flex-col rounded-2xl border border-border bg-card p-5 shadow-sm transition-all hover:shadow-md hover:border-primary/40">
      <div className="flex items-start gap-3">
        <div
          className={cn(
            "flex size-11 shrink-0 items-center justify-center rounded-xl",
            ready
              ? "bg-primary/10 text-primary"
              : processing
                ? "bg-accent text-accent-foreground"
                : "bg-danger/10 text-danger",
          )}
        >
          {processing ? (
            <Loader2 className="size-5 animate-spin" />
          ) : failed ? (
            <AlertTriangle className="size-5" />
          ) : (
            <FileText className="size-5" />
          )}
        </div>
        <div className="min-w-0 flex-1">
          <p className="truncate text-sm font-semibold" title={title}>
            {title}
          </p>
          <p className="truncate text-xs text-muted-foreground" title={doc.filename}>
            {doc.filename}
          </p>
        </div>
        {doc.plan && (
          <Badge variant="secondary">
            {difficultyLabel(doc.plan.difficulty)}
          </Badge>
        )}
      </div>

      <div className="mt-4 flex flex-wrap items-center gap-x-4 gap-y-1 text-xs text-muted-foreground">
        <span className="inline-flex items-center gap-1">
          <Clock className="size-3.5" />
          {formatDate(doc.created_at)}
        </span>
        {ready && (
          <span className="inline-flex items-center gap-1">
            <FileText className="size-3.5" />
            {doc.markdown_chars.toLocaleString()} chars
          </span>
        )}
        {doc.attemptCount > 0 && (
          <span className="inline-flex items-center gap-1">
            <Layers className="size-3.5" />
            {doc.attemptCount} attempt{doc.attemptCount > 1 ? "s" : ""}
          </span>
        )}
      </div>

      {failed && (
        <p className="mt-3 line-clamp-2 rounded-md bg-danger/10 px-2.5 py-1.5 text-xs text-danger">
          {doc.error ?? "Failed to process PDF"}
        </p>
      )}

      <div className="mt-4 flex items-center gap-2">
        {ready && !doc.plan && (
          <Button size="sm" className="gap-1.5" onClick={start}>
            Start learning
            <ChevronRight className="size-3.5" />
          </Button>
        )}
        {ready && doc.plan && (
          <>
            <Button size="sm" className="gap-1.5" onClick={start}>
              {doc.attemptCount > 0 ? (
                <>
                  <RefreshCw className="size-3.5" />
                  Retake
                </>
              ) : (
                <>
                  Continue
                  <ChevronRight className="size-3.5" />
                </>
              )}
            </Button>
            {doc.attemptCount > 0 && (
              <Button
                size="sm"
                variant="ghost"
                className="gap-1.5"
                onClick={start}
              >
                Review plan
              </Button>
            )}
          </>
        )}
        {processing && (
          <Button size="sm" variant="outline" disabled className="gap-1.5">
            <Loader2 className="size-3.5 animate-spin" />
            Parsing...
          </Button>
        )}
      </div>
    </div>
  );
}

import type { Difficulty } from "./types";

export function difficultyLabel(d: Difficulty): string {
  return d.charAt(0).toUpperCase() + d.slice(1);
}

export function difficultyColor(d: Difficulty): string {
  switch (d) {
    case "beginner":
      return "bg-success/15 text-success";
    case "intermediate":
      return "bg-primary/15 text-primary";
    case "advanced":
      return "bg-danger/15 text-danger";
  }
}

export function formatDate(iso: string): string {
  try {
    const d = new Date(iso.replace(" ", "T") + "Z");
    if (Number.isNaN(d.getTime())) return iso;
    return d.toLocaleString(undefined, {
      month: "short",
      day: "numeric",
      hour: "numeric",
      minute: "2-digit",
    });
  } catch {
    return iso;
  }
}

export function pluralize(n: number, singular: string, plural?: string): string {
  if (n === 1) return `${n} ${singular}`;
  return `${n} ${plural ?? singular + "s"}`;
}

import { useCallback, useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { Sparkles, Library, Loader2, ArrowRight } from "lucide-react";
import { UploadDropzone } from "#components/upload-dropzone";
import { DocumentCard } from "#components/document-card";
import { Skeleton } from "#components/ui/skeleton";
import { listDocuments, createPlan } from "#lib/api";
import type { DocumentSummary } from "#lib/types";

export function LibraryPage() {
  const [docs, setDocs] = useState<DocumentSummary[]>([]);
  const [loading, setLoading] = useState(true);
  const [planning, setPlanning] = useState<number | null>(null);
  const navigate = useNavigate();

  const refresh = useCallback(async () => {
    setLoading(true);
    try {
      const data = await listDocuments();
      setDocs(data);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    void refresh();
  }, [refresh]);

  useEffect(() => {
    const anyProcessing = docs.some((d) => d.status === "processing");
    if (anyProcessing) {
      const t = setTimeout(() => void refresh(), 3000);
      return () => clearTimeout(t);
    }
  }, [docs, refresh]);

  const handleUploaded = useCallback(async (documentId: number) => {
    await refresh();
    setPlanning(documentId);
    try {
      const plan = await createPlan(documentId);
      navigate(`/learn/${plan.id}`);
    } catch {
      // user will see doc in library; they can retry
    } finally {
      setPlanning(null);
    }
  }, [navigate, refresh]);

  return (
    <div className="space-y-10">
      <section className="relative overflow-hidden rounded-3xl border border-border bg-card p-8 sm:p-12">
        <div className="absolute inset-0 bg-grid-pattern opacity-60" />
        <div className="absolute inset-0 bg-radial-glow" />
        <div className="relative z-10 max-w-2xl">
          <span className="inline-flex items-center gap-1.5 rounded-full border border-primary/30 bg-primary/10 px-3 py-1 text-xs font-medium text-primary">
            <Sparkles className="size-3.5" />
            Human-in-the-loop learning agent
          </span>
          <h1 className="mt-4 text-3xl font-bold tracking-tight sm:text-4xl">
            Turn any PDF into an interactive lesson.
          </h1>
          <p className="mt-3 text-base text-muted-foreground">
            Upload a document, review the proposed learning path, then learn by
            answering quizzes with instant feedback, hints, and explanations —
            grounded in your PDF.
          </p>
          <div className="mt-6">
            <UploadDropzone onUploaded={handleUploaded} />
          </div>
        </div>
      </section>

      <section>
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <Library className="size-5 text-primary" />
            <h2 className="text-lg font-semibold tracking-tight">
              Your library
            </h2>
          </div>
          {docs.length > 0 && (
            <span className="text-xs text-muted-foreground">
              {docs.length} document{docs.length > 1 ? "s" : ""}
            </span>
          )}
        </div>

        {loading ? (
          <div className="mt-4 grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
            {Array.from({ length: 3 }).map((_, i) => (
              <Skeleton key={i} className="h-44 w-full rounded-2xl" />
            ))}
          </div>
        ) : docs.length === 0 ? (
          <div className="mt-4 rounded-2xl border border-dashed border-border bg-card p-10 text-center text-sm text-muted-foreground">
            No documents yet. Upload your first PDF above to begin.
          </div>
        ) : (
          <div className="mt-4 grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
            {docs.map((doc) => (
              <DocumentCard key={doc.id} doc={doc} />
            ))}
          </div>
        )}
      </section>

      {planning !== null && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-background/70 backdrop-blur-sm">
          <div className="flex items-center gap-3 rounded-2xl border border-border bg-card px-6 py-4 shadow-xl">
            <Loader2 className="size-5 animate-spin text-primary" />
            <div>
              <p className="text-sm font-medium">Drafting your lesson plan...</p>
              <p className="text-xs text-muted-foreground">
                Analyzing the PDF content with the agent.
              </p>
            </div>
          </div>
        </div>
      )}

      <footer className="flex items-center justify-center gap-2 pt-6 text-xs text-muted-foreground">
        <span>Built with LangChain, Fastify, SQLite, and Shadcn UI</span>
        <ArrowRight className="size-3" />
      </footer>
    </div>
  );
}

