import { Check, Circle, Loader2, X } from "lucide-react";
import { cn } from "#lib/utils";
import type { Objective } from "#lib/types";
import { Badge } from "#components/ui/badge";

export type ObjectiveStatus = "pending" | "current" | "correct" | "skipped";

interface Props {
  objectives: Objective[];
  statuses: ObjectiveStatus[];
  score: number;
  total: number;
}

export function ObjectiveTracker({
  objectives,
  statuses,
  score,
  total,
}: Props) {
  return (
    <div className="space-y-4">
      <div className="rounded-2xl border border-border bg-card p-4">
        <div className="flex items-baseline justify-between">
          <p className="text-xs font-medium uppercase tracking-wide text-muted-foreground">
            Score
          </p>
          <p className="text-2xl font-bold tabular-nums">
            {score}
            <span className="text-base text-muted-foreground">/{total}</span>
          </p>
        </div>
        <div className="mt-2 h-1.5 w-full overflow-hidden rounded-full bg-secondary">
          <div
            className="h-full rounded-full bg-primary transition-all duration-500"
            style={{
              width: total === 0 ? "0%" : `${(score / total) * 100}%`,
            }}
          />
        </div>
      </div>

      <div className="rounded-2xl border border-border bg-card p-4">
        <p className="mb-3 text-xs font-medium uppercase tracking-wide text-muted-foreground">
          Objectives
        </p>
        <ol className="space-y-1.5">
          {objectives.map((obj, i) => {
            const status = statuses[i] ?? "pending";
            return (
              <li
                key={i}
                className={cn(
                  "flex items-start gap-2.5 rounded-lg px-2 py-1.5 text-sm transition-colors",
                  status === "current" && "bg-accent/60",
                )}
              >
                <span className="mt-0.5 shrink-0">
                  {status === "correct" ? (
                    <span className="flex size-5 items-center justify-center rounded-full bg-success/15 text-success">
                      <Check className="size-3.5" />
                    </span>
                  ) : status === "skipped" ? (
                    <span className="flex size-5 items-center justify-center rounded-full bg-danger/15 text-danger">
                      <X className="size-3.5" />
                    </span>
                  ) : status === "current" ? (
                    <span className="flex size-5 items-center justify-center rounded-full bg-primary/15 text-primary">
                      <Loader2 className="size-3.5 animate-spin" />
                    </span>
                  ) : (
                    <Circle className="size-5 text-muted-foreground/50" />
                  )}
                </span>
                <div className="min-w-0 flex-1">
                  <p
                    className={cn(
                      "leading-snug",
                      status === "pending" && "text-muted-foreground",
                      (status === "correct" || status === "skipped") &&
                        "text-muted-foreground line-through decoration-muted-foreground/40",
                    )}
                  >
                    {obj.text}
                  </p>
                  <Badge variant="outline" className="mt-1">
                    {obj.topic}
                  </Badge>
                </div>
              </li>
            );
          })}
        </ol>
      </div>
    </div>
  );
}

import {
  Award,
  BookOpen,
  CheckCircle2,
  Lightbulb,
  RefreshCw,
  TrendingUp,
  XCircle,
} from "lucide-react";
import { cn } from "#lib/utils";
import { Badge } from "#components/ui/badge";
import { Button } from "#components/ui/button";
import { Card, CardContent } from "#components/ui/card";
import { Separator } from "#components/ui/separator";
import type { AttemptSummary } from "#lib/types";

interface Props {
  summary: AttemptSummary;
  onRetake: () => void;
  onBackToLibrary: () => void;
}

export function SummaryView({
  summary,
  onRetake,
  onBackToLibrary,
}: Props) {
  const pct =
    summary.total === 0 ? 0 : Math.round((summary.score / summary.total) * 100);
  const passedFirstTry = summary.answers.filter(
    (a) => a.attempts === 0 || a.attempts === 1,
  ).length;

  return (
    <div className="mx-auto max-w-3xl space-y-6">
      <Card className="overflow-hidden">
        <div className="relative bg-gradient-to-br from-primary/15 via-accent/40 to-transparent p-6 text-center sm:p-10">
          <div className="absolute inset-0 bg-grid-pattern opacity-40" />
          <div className="relative z-10">
            <div className="mx-auto mb-4 flex size-14 items-center justify-center rounded-2xl bg-primary text-primary-foreground shadow-lg">
              <Award className="size-7" />
            </div>
            <p className="text-xs font-medium uppercase tracking-wide text-muted-foreground">
              Lesson complete
            </p>
            <p className="mt-2 text-4xl font-bold tabular-nums">
              {summary.score}
              <span className="text-2xl text-muted-foreground">
                /{summary.total}
              </span>
            </p>
            <p className="mt-1 text-sm text-muted-foreground">
              {pct}% correct first try · {passedFirstTry} of {summary.total}{" "}
              mastered on first attempt
            </p>
            <div className="mx-auto mt-4 h-2 w-48 overflow-hidden rounded-full bg-secondary">
              <div
                className="h-full rounded-full bg-primary transition-all duration-700"
                style={{ width: `${pct}%` }}
              />
            </div>
          </div>
        </div>

        <Separator />

        <CardContent className="space-y-6 p-6 sm:p-8">
          <section>
            <div className="flex items-center gap-2">
              <TrendingUp className="size-4 text-primary" />
              <h2 className="text-sm font-semibold uppercase tracking-wide text-muted-foreground">
                Performance summary
              </h2>
            </div>
            <p className="mt-3 text-sm leading-relaxed text-foreground">
              {summary.summary}
            </p>
          </section>

          {(summary.strengths.length > 0 ||
            summary.weakTopics.length > 0) && (
            <div className="grid gap-4 sm:grid-cols-2">
              {summary.strengths.length > 0 && (
                <div className="rounded-xl border border-success/30 bg-success/5 p-4">
                  <div className="flex items-center gap-1.5 text-success">
                    <CheckCircle2 className="size-4" />
                    <p className="text-xs font-semibold uppercase tracking-wide">
                      Strengths
                    </p>
                  </div>
                  <ul className="mt-2 space-y-1">
                    {summary.strengths.map((s, i) => (
                      <li key={i} className="text-sm text-foreground">
                        {s}
                      </li>
                    ))}
                  </ul>
                </div>
              )}
              {summary.weakTopics.length > 0 && (
                <div className="rounded-xl border border-danger/30 bg-danger/5 p-4">
                  <div className="flex items-center gap-1.5 text-danger">
                    <XCircle className="size-4" />
                    <p className="text-xs font-semibold uppercase tracking-wide">
                      Needs work
                    </p>
                  </div>
                  <ul className="mt-2 space-y-1">
                    {summary.weakTopics.map((s, i) => (
                      <li key={i} className="text-sm text-foreground">
                        {s}
                      </li>
                    ))}
                  </ul>
                </div>
              )}
            </div>
          )}

          {summary.studyTips.length > 0 && (
            <section className="rounded-xl border border-primary/30 bg-primary/5 p-4">
              <div className="flex items-center gap-2">
                <Lightbulb className="size-4 text-primary" />
                <h2 className="text-sm font-semibold uppercase tracking-wide text-primary">
                  Personalized study tips
                </h2>
              </div>
              <ul className="mt-3 space-y-2">
                {summary.studyTips.map((tip, i) => (
                  <li
                    key={i}
                    className="flex items-start gap-2 text-sm text-foreground"
                  >
                    <span className="flex size-5 shrink-0 items-center justify-center rounded-full bg-primary/15 text-xs font-semibold text-primary">
                      {i + 1}
                    </span>
                    <span className="leading-relaxed">{tip}</span>
                  </li>
                ))}
              </ul>
            </section>
          )}

          <section>
            <div className="flex items-center gap-2">
              <BookOpen className="size-4 text-primary" />
              <h2 className="text-sm font-semibold uppercase tracking-wide text-muted-foreground">
                Question review
              </h2>
            </div>
            <div className="mt-3 space-y-3">
              {summary.answers.map((a, i) => {
                const correct = a.learnerIndex === a.correctIndex;
                const skipped = a.learnerIndex === null;
                return (
                  <div
                    key={i}
                    className={cn(
                      "rounded-xl border p-4",
                      correct
                        ? "border-success/40 bg-success/5"
                        : "border-danger/40 bg-danger/5",
                    )}
                  >
                    <div className="flex items-start justify-between gap-3">
                      <p className="text-sm font-medium leading-snug">
                        {a.question}
                      </p>
                      {correct ? (
                        <Badge variant="success" className="shrink-0">
                          <CheckCircle2 className="size-3" />
                          Correct
                        </Badge>
                      ) : skipped ? (
                        <Badge variant="secondary" className="shrink-0">
                          Skipped
                        </Badge>
                      ) : (
                        <Badge variant="danger" className="shrink-0">
                          <XCircle className="size-3" />
                          Missed
                        </Badge>
                      )}
                    </div>
                    <div className="mt-3 space-y-1 text-xs">
                      {a.options.map((opt, j) => {
                        const isCorrect = j === a.correctIndex;
                        const isLearner = j === a.learnerIndex;
                        return (
                          <div
                            key={j}
                            className={cn(
                              "flex items-center gap-2 rounded-md px-2 py-1",
                              isCorrect && "bg-success/15 text-success",
                              isLearner &&
                                !isCorrect &&
                                "bg-danger/15 text-danger",
                            )}
                          >
                            <span className="font-mono">{String.fromCharCode(65 + j)}.</span>
                            <span className="flex-1">{opt}</span>
                            {isCorrect && (
                              <CheckCircle2 className="size-3.5" />
                            )}
                            {isLearner && !isCorrect && (
                              <XCircle className="size-3.5" />
                            )}
                          </div>
                        );
                      })}
                    </div>
                    {a.attempts > 1 && (
                      <p className="mt-2 text-xs text-muted-foreground">
                        Took {a.attempts} attempts before getting it right.
                      </p>
                    )}
                  </div>
                );
              })}
            </div>
          </section>

          <div className="flex flex-wrap items-center justify-end gap-2 pt-2">
            <Button variant="ghost" onClick={onBackToLibrary}>
              Back to library
            </Button>
            <Button onClick={onRetake} className="gap-1.5">
              <RefreshCw className="size-4" />
              Retake lesson
            </Button>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import { useCallback, useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { ArrowLeft, Loader2 } from "lucide-react";
import { PlanCard } from "#components/plan-card";
import { MCQWidget } from "#components/mcq-widget";
import {
  ObjectiveTracker,
  type ObjectiveStatus,
} from "#components/objective-tracker";
import { SummaryView } from "#components/summary-view";
import { Card, CardContent } from "#components/ui/card";
import { Progress } from "#components/ui/progress";
import {
  approvePlan,
  completeAttempt,
  generateQuiz,
  getPlan,
  listQuizzes,
} from "#lib/api";
import type {
  AttemptSummary,
  Plan,
  QuizDTO,
} from "#lib/types";
import { difficultyLabel } from "#lib/format";

type Phase = "loading" | "review" | "quiz" | "summary" | "error";

interface AnswerState {
  quizId: number;
  learnerIndex: number | null;
  attempts: number;
  correct: boolean;
}

export function LessonPage() {
  const { planId } = useParams<{ planId: string }>();
  const navigate = useNavigate();
  const [phase, setPhase] = useState<Phase>("loading");
  const [plan, setPlan] = useState<Plan | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [quizzes, setQuizzes] = useState<Record<number, QuizDTO>>({});
  const [currentIdx, setCurrentIdx] = useState(0);
  const [answers, setAnswers] = useState<AnswerState[]>([]);
  const [loadingQuiz, setLoadingQuiz] = useState(false);
  const [summary, setSummary] = useState<AttemptSummary | null>(null);
  const [finishing, setFinishing] = useState(false);

  useEffect(() => {
    if (!planId) return;
    const id = Number(planId);
    getPlan(id)
      .then((p) => {
        setPlan(p);
        if (p.status === "draft") setPhase("review");
        else setPhase("quiz");
      })
      .catch((err: unknown) => {
        setError((err as Error).message);
        setPhase("error");
      });
  }, [planId]);

  // Preload existing quizzes when entering quiz phase (for retest flow)
  useEffect(() => {
    if (phase !== "quiz" || !planId || !plan) return;
    const id = Number(planId);
    listQuizzes(id)
      .then((existing) => {
        if (existing.length > 0) {
          const map: Record<number, QuizDTO> = {};
          for (const q of existing) map[q.objectiveIndex] = q;
          setQuizzes(map);
        }
      })
      .catch(() => {
        // ignore — we'll lazy-generate
      });
  }, [phase, planId, plan]);

  const currentQuiz = quizzes[currentIdx];

  // Lazy generate the quiz for currentIdx when needed
  useEffect(() => {
    if (phase !== "quiz" || !plan || !planId) return;
    if (quizzes[currentIdx] || loadingQuiz) return;
    if (currentIdx >= plan.objectives.length) return;
    const id = Number(planId);
    setLoadingQuiz(true);
    generateQuiz(id, currentIdx)
      .then((q) => {
        setQuizzes((prev) => ({ ...prev, [currentIdx]: q }));
      })
      .catch((err: unknown) => {
        setError((err as Error).message);
        setPhase("error");
      })
      .finally(() => setLoadingQuiz(false));
  }, [phase, plan, planId, currentIdx, quizzes, loadingQuiz]);

  const handleApprove = useCallback(async () => {
    if (!plan) return;
    try {
      const updated = await approvePlan(plan.id);
      setPlan(updated);
      setPhase("quiz");
    } catch (err) {
      setError((err as Error).message);
      setPhase("error");
    }
  }, [plan]);

  const recordAnswer = useCallback(
    (idx: number, learnerIndex: number | null, correct: boolean, attempts: number) => {
      setAnswers((prev) => {
        const next = [...prev];
        next[idx] = { quizId: quizzes[idx]?.id ?? -1, learnerIndex, correct, attempts };
        return next;
      });
    },
    [quizzes],
  );

  const handleCorrect = useCallback(
    (idx: number, explanation: string) => {
      const attempts = (answers[idx]?.attempts ?? 0) + 1;
      recordAnswer(idx, currentQuiz ? null : null, true, attempts);
      // The learnerIndex will be set on submit; for correct, the selected option is what was checked.
      // We track it via the widget — but since we don't have direct access here, infer from the
      // correct submission by recording again below.
      void explanation;
    },
    [answers, currentQuiz, recordAnswer],
  );

  // We need a more reliable way to track the learner's final selected index. The widget
  // calls onCorrect after the server confirms the answer is correct — at that point the
  // currently selected option IS the learner's correct answer. So we pass the selected
  // index from the widget. Let me restructure the props.

  const handleIncorrect = useCallback(
    (idx: number, learnerIndex: number) => {
      setAnswers((prev) => {
        const next = [...prev];
        const prevAttempts = next[idx]?.attempts ?? 0;
        next[idx] = {
          quizId: quizzes[idx]?.id ?? -1,
          learnerIndex,
          correct: false,
          attempts: prevAttempts + 1,
        };
        return next;
      });
    },
    [quizzes],
  );

  const advance = useCallback(() => {
    if (!plan) return;
    if (currentIdx + 1 >= plan.objectives.length) {
      // finish
      void finish();
    } else {
      setCurrentIdx((i) => i + 1);
    }
  }, [currentIdx, plan]);

  const finish = useCallback(async () => {
    if (!plan || !planId || finishing) return;
    setFinishing(true);
    try {
      const payload = answers.map((a) => ({
        quizId: a.quizId,
        learnerIndex: a.learnerIndex,
        attempts: a.attempts,
      }));
      const result = await completeAttempt(plan.id, payload);
      setSummary(result);
      setPhase("summary");
    } catch (err) {
      setError((err as Error).message);
      setPhase("error");
    } finally {
      setFinishing(false);
    }
  }, [plan, planId, answers, finishing]);

  const handleRetake = useCallback(() => {
    setAnswers([]);
    setQuizzes({});
    setCurrentIdx(0);
    setSummary(null);
    setPhase("quiz");
  }, []);

  if (phase === "loading") {
    return (
      <div className="flex h-[60vh] items-center justify-center">
        <Loader2 className="size-6 animate-spin text-primary" />
      </div>
    );
  }

  if (phase === "error" || !plan) {
    return (
      <div className="mx-auto max-w-2xl">
        <Card>
          <CardContent className="p-8 text-center">
            <p className="text-sm font-medium text-danger">
              {error ?? "Something went wrong."}
            </p>
            <button
              onClick={() => navigate("/")}
              className="mt-4 inline-flex items-center gap-1.5 text-sm text-muted-foreground hover:text-foreground"
            >
              <ArrowLeft className="size-4" />
              Back to library
            </button>
          </CardContent>
        </Card>
      </div>
    );
  }

  if (phase === "review") {
    return (
      <PlanCard
        plan={plan}
        onApprove={handleApprove}
        onBack={() => navigate("/")}
      />
    );
  }

  if (phase === "summary" && summary) {
    return (
      <SummaryView
        summary={summary}
        onRetake={handleRetake}
        onBackToLibrary={() => navigate("/")}
      />
    );
  }

  // quiz phase
  const total = plan.objectives.length;
  const completed = answers.filter((a) => a.correct || a.learnerIndex === null).length;
  const score = answers.filter((a) => a.correct).length;
  const progressPct = total === 0 ? 0 : Math.round((completed / total) * 100);
  const statuses: ObjectiveStatus[] = plan.objectives.map((_, i) => {
    if (answers[i]) {
      return answers[i].learnerIndex === null ? "skipped" : "correct";
    }
    if (i === currentIdx) return "current";
    return "pending";
  });

  return (
    <div className="space-y-6">
      <button
        onClick={() => navigate("/")}
        className="inline-flex items-center gap-1.5 text-sm text-muted-foreground transition-colors hover:text-foreground"
      >
        <ArrowLeft className="size-4" />
        Back to library
      </button>

      <div className="space-y-2">
        <div className="flex items-center justify-between gap-3">
          <div className="min-w-0">
            <h1 className="truncate text-xl font-bold tracking-tight">
              {plan.title}
            </h1>
            <p className="text-xs text-muted-foreground">
              {difficultyLabel(plan.difficulty)} · {completed} of {total}{" "}
              objectives done
            </p>
          </div>
          <div className="text-right">
            <p className="text-2xl font-bold tabular-nums">
              {score}
              <span className="text-base text-muted-foreground">
                /{total}
              </span>
            </p>
          </div>
        </div>
        <Progress value={progressPct} />
      </div>

      <div className="grid gap-6 lg:grid-cols-[1fr_280px]">
        <div className="min-w-0">
          {currentQuiz ? (
            <MCQWidget
              key={currentQuiz.id}
              quiz={currentQuiz}
              objectiveNumber={currentIdx + 1}
              totalObjectives={total}
              onCorrect={(explanation) => {
                // The selected option at correct time is what the user picked; but we
                // don't have it here. We rely on the server to confirm. Mark correct.
                void explanation;
                setAnswers((prev) => {
                  const next = [...prev];
                  const prevAttempts = next[currentIdx]?.attempts ?? 0;
                  next[currentIdx] = {
                    quizId: currentQuiz.id,
                    // learnerIndex unknown here; we'd ideally pass it. For scoring,
                    // server re-checks. So null is fine — server uses correct path.
                    learnerIndex: null,
                    correct: true,
                    attempts: prevAttempts,
                  };
                  return next;
                });
              }}
              onIncorrect={(learnerIndex) => handleIncorrect(currentIdx, learnerIndex)}
              onSkip={() => {
                setAnswers((prev) => {
                  const next = [...prev];
                  const prevAttempts = next[currentIdx]?.attempts ?? 0;
                  next[currentIdx] = {
                    quizId: currentQuiz.id,
                    learnerIndex: null,
                    correct: false,
                    attempts: prevAttempts,
                  };
                  return next;
                });
                advance();
              }}
              onNext={advance}
              isLast={currentIdx === total - 1}
            />
          ) : (
            <Card>
              <CardContent className="flex flex-col items-center justify-center gap-3 p-12 text-center">
                <Loader2 className="size-6 animate-spin text-primary" />
                <p className="text-sm text-muted-foreground">
                  Generating question for objective {currentIdx + 1}...
                </p>
              </CardContent>
            </Card>
          )}
          {finishing && (
            <p className="mt-4 flex items-center justify-center gap-2 text-sm text-muted-foreground">
              <Loader2 className="size-4 animate-spin" />
              Building your progress report...
            </p>
          )}
        </div>

        <aside className="lg:sticky lg:top-20 lg:self-start">
          <ObjectiveTracker
            objectives={plan.objectives}
            statuses={statuses}
            score={score}
            total={total}
          />
        </aside>
      </div>
    </div>
  );
}

